import type { I18n } from '../i18n';

import { getI18n as getI18nCore } from '@nordic/core-context';

import { throwI18nNotInitializedError } from '../error';

/**
 * Provides an instance of the `I18n` class anywhere after `createNordicI18nMiddlewares` has run, including React Components.
 *
 * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-i18n#geti18n-getter | Documentation}
 *
 * @example
 *
 * import { getI18n } from 'nordic/i18n';
 *
 * const SomeComponent = () => {
 *   const i18n = getI18n();
 *
 *   return (
 *     <div>
 *       <p>{i18n.gettext('Some text')}</p>
 *       <p>Other text</p>
 *     </div>
 *   );
 * };
 */
export function getI18n() {
  const i18n = getI18nCore<I18n>();

  if (__DEV__ && !i18n) {
    throwI18nNotInitializedError();
  }

  return i18n!;
}
